features.snippet:
module InoutCombRead(
  inout wire c,
  output logic q_comb
);
  always_comb q_comb = c;
endmodule

module InoutAssignDrive(
  inout wire c,
  input logic c_drv
);
  assign c = c_drv;
endmodule

module InoutFFSample(
  inout wire c,
  input logic clk,
  output logic q_ff
);
  always_ff @(posedge clk)
    q_ff <= c;
endmodule

module InoutFeedback(
  inout wire c
);
  logic c_next;
  always_comb c_next = ~c;
endmodule

module InoutReadWrite(
  inout wire c,
  input logic clk,
  output logic q_comb,
  output logic q_ff,
  output logic c_drv
);
  logic c_next;
  assign c = c_drv;
  always_comb c_next = ~c;
  always_comb q_comb = c;
  always_ff @(posedge clk) begin
    q_ff <= c;
    c_drv <= c_next;
  end
endmodule
